-- settings.bind
hl.bind("SUPER + return", (hl.dsp.exec_cmd( "kitty" )), {})
hl.bind("SUPER + Q", (hl.dsp.exec_cmd( "librewolf" )), {})
hl.bind("SUPER + P", (hl.dsp.exec_cmd( "hyprpicker" )), {})
hl.bind("SUPER + E", (hl.dsp.exec_cmd( "kitty yazi" )), {})
