hl.bind("SUPER + SHIFT + F", (hl.dsp.window.float({ action = "toggle" })), {})
hl.bind("SUPER + V", (hl.dsp.exec_cmd( "kitty --class clipse -e clipse" )), {})
hl.bind("SUPER + N", (hl.dsp.exec_cmd( "swaync-client -t" )), {})
hl.bind("SUPER + SHIFT + N", (hl.dsp.exec_cmd( "kitty impala" )), {})
hl.bind("XF86AudioRaiseVolume", (hl.dsp.exec_cmd( "wpctl set-volume -l 1 @DEFAULT_AUDIO_SINK@ 5%+" )), {
  ["locked"] = true,
  ["repeating"] = true
})
hl.bind("XF86AudioLowerVolume", (hl.dsp.exec_cmd( "wpctl set-volume @DEFAULT_AUDIO_SINK@ 5%-" )), {
  ["locked"] = true,
  ["repeating"] = true
})
hl.bind("XF86AudioMute", (hl.dsp.exec_cmd( "wpctl set-mute @DEFAULT_AUDIO_SINK@ toggle" )), {
  ["locked"] = true,
  ["repeating"] = true
})
hl.bind("XF86AudioMicMute", (hl.dsp.exec_cmd( "wpctl set-mute @DEFAULT_AUDIO_SOURCE@ toggle" )), {
  ["locked"] = true,
  ["repeating"] = true
})
hl.bind("XF86MonBrightnessUp", (hl.dsp.exec_cmd( "brightnessctl -d intel_backlight set 5%+" )), {
  ["locked"] = true,
  ["repeating"] = true
})
hl.bind("XF86MonBrightnessDown", (hl.dsp.exec_cmd( "brightnessctl -d intel_backlight set 5%-" )), {
  ["locked"] = true,
  ["repeating"] = true
})
hl.bind("XF86AudioNext", (hl.dsp.exec_cmd( "playerctl next" )), {
  ["locked"] = true
})
hl.bind("XF86AudioPause", (hl.dsp.exec_cmd( "playerctl play-pause" )), {
  ["locked"] = true
})
hl.bind("XF86AudioPlay", (hl.dsp.exec_cmd( "playerctl play-pause" )), {
  ["locked"] = true
})
hl.bind("XF86AudioPrev", (hl.dsp.exec_cmd( "playerctl previous" )), {
  ["locked"] = true
})
hl.bind("SUPER + h", (hl.dsp.focus({ direction = "left" })), {})
