hl.bind("SUPER + SHIFT + 3", (hl.dsp.window.move({ workspace = 3 })), {})
hl.bind("SUPER + SHIFT + 4", (hl.dsp.window.move({ workspace = 4 })), {})
hl.bind("SUPER + SHIFT + h", (hl.dsp.focus({ workspace = "e-1" })), {})
