-- settings.on
hl.on("hyprland.start", (function()
						hl.exec_cmd("dbus-update-activation-environment --systemd --all")
						hl.exec_cmd("polkit-agent")
						hl.exec_cmd("rfkill unblock bluetooth")
						hl.exec_cmd("hyprlock")
						hl.exec_cmd("awww-daemon")
						hl.exec_cmd("bash -c 'sleep 0.5; awww img --transition-type center --transition-angle 30 --transition-step 90 --transition-fps 60 --transition-duration 1 ~/nixos-dotfiles/assets/wallpapers/wallpaper.jpg'")
						hl.exec_cmd("swaync")
            hl.exec_cmd("bash -c 'sleep 3; waybar'")
						--hl.exec_cmd("bash -c 'sleep 3; pkill waybar; if hyprctl monitors | grep -q DP-1; then waybar -c ~/.config/waybar/config-monitor; else waybar -c ~/.config/waybar/config-laptop; fi'")
					end))

-- extraConfig
			hl.config({ xwayland = { force_zero_scaling = true } })
			hl.config({ cursor = { no_hardware_cursors = true } })

			hl.config({
				general = {
					layout  = "scrolling", --Niri like scrolling perfection
					gaps_in     = 8,
					gaps_out    = 16,
					border_size = 0,
					col = {
						active_border   = "rgba(3f3f68ff)",
						inactive_border = "rgba(3f3f68aa)",
					},
				},
			})

			hl.config({
				scrolling = {
					fullscreen_on_one_column = true,
					column_width             = 0.5,
					follow_focus             = true,
					follow_min_visible       = 0,
					wrap_focus               = true,
					explicit_column_widths   = "0.333, 0.5, 0.9, 1.0",
				},
			})
			
			hl.config({
        decoration = {
          rounding       = 10,
          rounding_power = 2, 

          active_opacity   = 0.850000,
          inactive_opacity = 0.850000,

          blur = {
            enabled  = true,
						new_optimizations = true,
            size     = 4,
            passes   = 2,
          },
        },
      })

			hl.config({ misc = { background_color = "rgb(0, 0, 0)" } })

			hl.workspace_rule({ workspace = "1", monitor = "DP-1", default = true, persistent = true })
			hl.workspace_rule({ workspace = "2", monitor = "DP-1", persistent = true })
			hl.workspace_rule({ workspace = "3", monitor = "eDP-1", persistent = true })
			hl.workspace_rule({ workspace = "4", monitor = "eDP-1", persistent = true })

			hl.window_rule({ match = { class = "clipse" }, float = true })
			hl.window_rule({ match = { class = "clipse" }, size = { 622, 652 } })

			hl.curve("snappy", { type = "bezier", points = { {0.25, 0.1}, {0.25, 1} } })
			hl.animation({ leaf = "windows",    enabled = true, speed = 3, bezier = "snappy" })

			--snappy workspace switching
			hl.animation({ leaf = "workspaces", enabled = false })

